(() => {
if (!document.body.classList.contains("page-rafting")) return;
try {
document.addEventListener("DOMContentLoaded", function () {
const languageButtons =
document.querySelectorAll(".language-button");
function changeLanguage(language) {
document.body.dataset.lang = language;
document.documentElement.lang = language;
languageButtons.forEach(function (button) {
const isActive =
button.dataset.language === language;
button.classList.toggle("active", isActive);
button.setAttribute(
"aria-pressed",
String(isActive)
);
});
localStorage.setItem(
"imsfrane-language",
language
);
}
const savedLanguage =
localStorage.getItem("imsfrane-language");
if (savedLanguage === "fr" || savedLanguage === "en") {
changeLanguage(savedLanguage);
}
languageButtons.forEach(function (button) {
button.addEventListener("click", function () {
changeLanguage(button.dataset.language);
});
});
const faqItems =
document.querySelectorAll(".rafting-faq-item");
faqItems.forEach(function (item) {
const question =
item.querySelector(".rafting-faq-question");
if (!question) {
return;
}
question.addEventListener("click", function () {
const isOpen =
item.classList.contains("open");
faqItems.forEach(function (otherItem) {
otherItem.classList.remove("open");
const otherQuestion =
otherItem.querySelector(
".rafting-faq-question"
);
if (otherQuestion) {
otherQuestion.setAttribute(
"aria-expanded",
"false"
);
}
});
if (!isOpen) {
item.classList.add("open");
question.setAttribute(
"aria-expanded",
"true"
);
}
});
});
const hero =
document.querySelector(".rafting-hero");
if (!hero) {
return;
}
const slides =
hero.querySelectorAll(".slide");
const previousButton =
hero.querySelector(".slider-btn.prev");
const nextButton =
hero.querySelector(".slider-btn.next");
const dotsContainer =
hero.querySelector(".slider-dots");
if (!slides.length || !dotsContainer) {
return;
}
let currentSlide = 0;
let sliderTimer = null;
if (!dotsContainer.children.length) {
slides.forEach(function (_, index) {
const dot =
document.createElement("button");
dot.type = "button";
dot.className =
index === 0
? "dot active"
: "dot";
dot.setAttribute(
"aria-label",
"Open image " + (index + 1)
);
dot.addEventListener("click", function () {
showSlide(index);
restartSlider();
});
dotsContainer.appendChild(dot);
});
}
const dots =
dotsContainer.querySelectorAll(".dot");
function showSlide(index) {
slides[currentSlide].classList.remove("active");
if (dots[currentSlide]) {
dots[currentSlide].classList.remove("active");
}
currentSlide =
(index + slides.length) % slides.length;
slides[currentSlide].classList.add("active");
if (dots[currentSlide]) {
dots[currentSlide].classList.add("active");
}
}
function nextSlide() {
showSlide(currentSlide + 1);
}
function previousSlide() {
showSlide(currentSlide - 1);
}
function restartSlider() {
window.clearInterval(sliderTimer);
sliderTimer =
window.setInterval(nextSlide, 5000);
}
if (previousButton) {
previousButton.addEventListener(
"click",
function () {
previousSlide();
restartSlider();
}
);
}
if (nextButton) {
nextButton.addEventListener(
"click",
function () {
nextSlide();
restartSlider();
}
);
}
restartSlider();
});
} catch (error) {
console.error("Imsfrane rafting module error:", error);
}
})();
